  1	import React, { FC } from 'react';
  2	import { RouteComponentProps } from 'react-router';
  3	import { useNMStateTranslation } from 'src/utils/hooks/useNMStateTranslation';
  4	
  5	import {
  6	  DescriptionList,
  7	  DescriptionListDescription,
  8	  DescriptionListGroup,
  9	  DescriptionListTerm,
 10	  PageSection,
 11	  PageSectionVariants,
 12	  Title,
 13	} from '@patternfly/react-core';
 14	import { NodeNetworkConfigurationInterface, V1NodeNetworkConfigurationPolicy } from '@types';
 15	
 16	type PolicyDetailsPageProps = RouteComponentProps<{
 17	  ns: string;
 18	  name: string;
 19	}> & {
 20	  obj?: V1NodeNetworkConfigurationPolicy;
 21	};
 22	
 23	const PolicyDetailsPage: FC<PolicyDetailsPageProps> = ({ obj: policy }) => {
 24	  const { t } = useNMStateTranslation();
 25	
 26	  const firstInterface = policy?.spec?.desiredState
 27	    ?.interfaces?.[0] as NodeNetworkConfigurationInterface;
 28	
 29	  const dnsResolver = policy?.spec?.desiredState?.['dns-resolver'];
 30	
 31	  const description = policy?.metadata?.annotations?.['description'];
 32	
 33	  return (
 34	    <div>
 35	      <PageSection variant={PageSectionVariants.light}>
 36	        <Title headingLevel="h2" className="co-section-heading">
 37	          {t('Policy details')}
 38	        </Title>
 39	        <DescriptionList className="pf-c-description-list">
 40	          <DescriptionListGroup className="pf-c-description-list__group">
 41	            <DescriptionListTerm className="pf-c-description-list__term">
 42	              {t('Name')}
 43	            </DescriptionListTerm>
 44	            <DescriptionListDescription className="pf-c-description-list__description">
 45	              {policy?.metadata?.name}
 46	            </DescriptionListDescription>
 47	          </DescriptionListGroup>
 48	          {description && (
 49	            <DescriptionListGroup className="pf-c-description-list__group">
 50	              <DescriptionListTerm className="pf-c-description-list__term">
 51	                {t('Description')}
 52	              </DescriptionListTerm>
 53	              <DescriptionListDescription className="pf-c-description-list__description">
 54	                {description}
 55	              </DescriptionListDescription>
 56	            </DescriptionListGroup>
 57	          )}
 58	          {firstInterface && (
 59	            <>
 60	              <DescriptionListGroup className="pf-c-description-list__group">
 61	                <DescriptionListTerm className="pf-c-description-list__term">
 62	                  {t('Type')}
 63	                </DescriptionListTerm>
 64	                <DescriptionListDescription className="pf-c-description-list__description">
 65	                  {firstInterface?.type}
 66	                </DescriptionListDescription>
 67	              </DescriptionListGroup>
 68	              <DescriptionListGroup className="pf-c-description-list__group">
 69	                <DescriptionListTerm className="pf-c-description-list__term">
 70	                  {t('Network state')}
 71	                </DescriptionListTerm>
 72	                <DescriptionListDescription className="pf-c-description-list__description">
 73	                  {firstInterface?.state}
 74	                </DescriptionListDescription>
 75	              </DescriptionListGroup>
 76	              <DescriptionListGroup className="pf-c-description-list__group">
 77	                <DescriptionListTerm className="pf-c-description-list__term">
 78	                  {t('IP configuration')}
 79	                </DescriptionListTerm>
 80	                <DescriptionListDescription className="pf-c-description-list__description">
 81	                  {!!firstInterface?.ipv4 && t('IPv4')}
 82	                  {!!firstInterface?.ipv6 && !firstInterface?.ipv4 && t('IPv6')}
 83	                  {!firstInterface?.ipv6 && !firstInterface?.ipv4 && t('None')}
 84	                </DescriptionListDescription>
 85	              </DescriptionListGroup>
 86	            </>
 87	          )}
 88	
 89	          {dnsResolver?.config?.search && (
 90	            <>
 91	              <DescriptionListGroup className="pf-c-description-list__group">
 92	                <DescriptionListTerm className="pf-c-description-list__term">
 93	                  {t('Search')}
 94	                </DescriptionListTerm>
 95	                <DescriptionListDescription className="pf-c-description-list__description">
 96	                  {dnsResolver?.config?.search.join(', ')}
 97	                </DescriptionListDescription>
 98	              </DescriptionListGroup>
 99	            </>
100	          )}
101	
102	          {dnsResolver?.config?.server && (
103	            <>
104	              <DescriptionListGroup className="pf-c-description-list__group">
105	                <DescriptionListTerm className="pf-c-description-list__term">
106	                  {t('Server')}
107	                </DescriptionListTerm>
108	                <DescriptionListDescription className="pf-c-description-list__description">
109	                  {dnsResolver?.config?.server.join(', ')}
110	                </DescriptionListDescription>
111	              </DescriptionListGroup>
112	            </>
113	          )}
114	        </DescriptionList>
115	      </PageSection>
116	    </div>
117	  );
118	};
119	
120	export default PolicyDetailsPage;

